{
  "module": "01-layout.md",
  "group": "01 — Layout & Container Components",
  "apiCount": 11,
  "apis": [
    {
      "name": "Column",
      "purpose": "垂直方向线性布局容器，用于构建页面纵向结构",
      "anchor": "column",
      "status": "found"
    },
    {
      "name": "Row",
      "purpose": "水平方向线性布局容器，用于构建页面横向结构",
      "anchor": "row",
      "status": "found"
    },
    {
      "name": "Stack",
      "purpose": "堆叠容器，子组件按顺序入栈后一个覆盖前一个，适合重叠元素布局",
      "anchor": "stack",
      "status": "found"
    },
    {
      "name": "Flex",
      "purpose": "弹性布局容器，高效排列对齐子元素并分配剩余空间",
      "anchor": "flex",
      "status": "found"
    },
    {
      "name": "RelativeContainer",
      "purpose": "相对布局组件，通过 alignRules 定义子组件相对于容器或其他元素的对齐规则",
      "anchor": "relativecontainer",
      "status": "found"
    },
    {
      "name": "Scroll",
      "purpose": "可滚动容器组件，子组件尺寸超出父容器时内容可滚动",
      "anchor": "scroll",
      "status": "found"
    },
    {
      "name": "List",
      "purpose": "列表容器，适合连续多行呈现同类数据，支持懒加载",
      "anchor": "list",
      "status": "found"
    },
    {
      "name": "Grid",
      "purpose": "网格容器，由行和列分割单元格组成，支持跨行跨列",
      "anchor": "grid",
      "status": "found"
    },
    {
      "name": "Divider",
      "purpose": "分割线组件，分隔不同内容块",
      "anchor": "divider",
      "status": "found"
    },
    {
      "name": "Blank",
      "purpose": "空白填充组件，在父容器主轴方向自动填充剩余空间",
      "anchor": "blank",
      "status": "found"
    },
    {
      "name": "ScrollBar",
      "purpose": "滚动条组件，配合可滚动组件（List/Scroll/Grid等）显示自定义滚动条",
      "anchor": "scrollbar",
      "status": "found"
    }
  ],
  "notableFindings": [
    "所有组件均为 ArkUI 内置组件，无需 import 语句",
    "Flex 存在二次布局，性能敏感场景建议用 Column/Row 替代",
    "Column/Row 未设主轴大小时默认自适应子节点；Flex 默认撑满父容器",
    "RelativeContainer 子组件通过 alignRules 属性定义锚点对齐",
    "List 推荐与 LazyForEach/virtualScroll-Repeat 配合实现懒加载",
    "Grid columnsTemplate 支持 fr 比例单位及 repeat(auto-fit/fill/stretch) 自适应",
    "Blank 仅在 Row/Column/Flex 父容器中生效",
    "DynamicLayout (API 24+) 存在于目标目录但不在本 api_list 中，建议单独成模块"
  ],
  "missingApis": []
}

