      "name": "@Watch",
      "purpose": "Watch state variable changes for wheel spin completion and filter update reactions",
      "anchor": "watch",
      "status": "found"
    },
    {
      "name": "@ObjectLink",
      "purpose": "Observe property changes on @Observed-decorated objects from child components",
      "anchor": "objectlink",
      "status": "found"
    },
    {
      "name": "@StorageLink",
      "purpose": "Two-way binding component variable to AppStorage for app-level shared state",
      "anchor": "storagelink",
      "status": "found"
    },
    {
      "name": "@LocalStorageLink",
      "purpose": "Two-way binding component variable to LocalStorage for page-level shared state",
      "anchor": "localstoragelink",
      "status": "found"
    },
    {
      "name": "AppStorage",
      "purpose": "App-global UI state storage for active tab, user preferences, shared configuration",
      "anchor": "appstorage",
      "status": "found"
    },
    {
      "name": "LocalStorage",
      "purpose": "Page-level UI state storage for scoped state within a UIAbility context",
      "anchor": "localstorage",
      "status": "found"
    },
    {
      "name": "PersistentStorage",
      "purpose": "Persist data that survives app restarts (dish database, ingredient list, meal logs)",
      "anchor": "persistentstorage",
      "status": "found"
    },
    {
      "name": "@Observed",
      "purpose": "Make class property changes observable for @ObjectLink in child components",
      "anchor": "observed",
      "status": "found"
    },
    {
      "name": "Environment",
      "purpose": "Device environment query (language, color mode, font scale) stored into AppStorage",
      "anchor": "environment",
      "status": "found"
    },
    {
      "name": "@Env",
      "purpose": "System UI environment variable decorator (API 22+) for breakpoint, window size, avoid area",
      "anchor": "env",
      "status": "found"
    }
  ],
  "notableFindings": [
    "V1 decorators (@State/@Prop/@Link/@Provide/@Consume/@ObjectLink/@Observed) have no standalone API reference docs - their signatures follow development guide conventions",
    "API 12+ introduces AppStorageV2/PersistenceV2 via import { AppStorageV2, PersistenceV2 } from '@kit.ArkUI'",
    "@Watch('callbackName') accepts a string referencing a method name on the same component",
    "@Env (API 22+) is distinct from Environment API - it decorates component properties for responsive breakpoint/window size/avoid area",
    "AppStorage/LocalStorage support Map, Set, Date, null, undefined, union types from API 12",
    "PersistentStorage.persistProp/persistProps are the current API (v10+); PersistProp/PersistProps are deprecated (v7-v9)",
    "Recommend V1 decorators for Eat-What cross-component state, AppStorage for global state, PersistentStorage for dish database",
    "@Watch is suitable for wheel spin completion reactions and filter change side effects"
  ],
  "missingApis": []
}

